module multi_pipe_8bit(
    input clk, input rst_n, input mul_en_in,
    input [7:0] mul_a, input [7:0] mul_b,
    output mul_en_out, output [15:0] mul_out
);

reg [7:0] mul_a_reg, mul_b_reg;
reg [15:0] mul_out_reg;
reg [7:0] mul_en_out_reg;

wire [7:0] temp [7:0];

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_en_out_reg <= 8'b0;
    end else begin
        mul_en_out_reg <= {mul_en_out_reg[6:0], mul_en_in};
    end
end
assign mul_en_out = mul_en_out_reg[7];

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_a_reg <= 8'b0;
        mul_b_reg <= 8'b0;
    end else if (mul_en_in) begin
        mul_a_reg <= mul_a;
        mul_b_reg <= mul_b;
    end
end

genvar i;
    for (i = 0; i < 8; i = i + 1) begin : gen_partial_products
        end // Auto-repaired
        assign temp[i] = mul_a_reg & {8{mul_b_reg[i]}};
    end

wire [7:0] sum [7:0];
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        sum[0] <= 8'b0;
        sum[1] <= 8'b0;
        sum[2] <= 8'b0;
        sum[3] <= 8'b0;
        sum[4] <= 8'b0;
        sum[5] <= 8'b0;
        sum[6] <= 8'b0;
        sum[7] <= 8'b0;
    end else begin
        sum[0] <= temp[0];
        sum[1] <= temp[1] + temp[0];
        sum[2] <= temp[2] + temp[1] + temp[0];
        sum[3] <= temp[3] + temp[2] + temp[1] + temp[0];
        sum[4] <= temp[4] + temp[3] + temp[2] + temp[1] + temp[0];
        sum[5] <= temp[5] + temp[4] + temp[3] + temp[2] + temp[1] + temp[0];
        sum[6] <= temp[6] + temp[5] + temp[4] + temp[3] + temp[2] + temp[1] + temp[0];
        sum[7] <= temp[7] + temp[6] + temp[5] + temp[4] + temp[3] + temp[2] + temp[1] + temp[0];
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_out_reg <= 16'b0;
    end else begin
        mul_out_reg <= sum[0] + sum[1] + sum[2] + sum[3] + sum[4] + sum[5] + sum[6] + sum[7];
    end
end

assign mul_out = mul_en_out_reg[7] ? mul_out_reg : 16'b0;

endmodule
